#[pymodule]
pub fn _native(m: &Bound<'_, PyModule>) -> PyResult<()> {
    m.add_class::<ExtractionPattern>()?;
    m.add_class::<ExtractionConfig>()?;
    m.add_class::<CaptureResult>()?;
    m.add_class::<MatchResult>()?;
    m.add_class::<PatternResult>()?;
    m.add_class::<ExtractionResult>()?;
    m.add_class::<PatternValidation>()?;
    m.add_class::<ValidationResult>()?;
    m.add_class::<Span>()?;
    m.add_class::<ProcessResult>()?;
    m.add_class::<FileMetrics>()?;
    m.add_class::<StructureItem>()?;
    m.add_class::<CommentInfo>()?;
    m.add_class::<DocstringInfo>()?;
    m.add_class::<DocSection>()?;
    m.add_class::<ImportInfo>()?;
    m.add_class::<ExportInfo>()?;
    m.add_class::<SymbolInfo>()?;
    m.add_class::<Diagnostic>()?;
    m.add_class::<CodeChunk>()?;
    m.add_class::<ChunkContext>()?;
    m.add_class::<NodeInfo>()?;
    m.add_class::<PackConfig>()?;
    m.add_class::<ProcessConfig>()?;
    m.add_class::<QueryMatch>()?;
    m.add_class::<LanguageRegistry>()?;
    m.add_class::<ParserManifest>()?;
    m.add_class::<PlatformBundle>()?;
    m.add_class::<LanguageInfo>()?;
    m.add_class::<DownloadManager>()?;
    m.add_class::<Language>()?;
    m.add_class::<Parser>()?;
    m.add_class::<Tree>()?;
    m.add_class::<CaptureOutput>()?;
    m.add_class::<StructureKind>()?;
    m.add_class::<CommentKind>()?;
    m.add_class::<DocstringFormat>()?;
    m.add_class::<ExportKind>()?;
    m.add_class::<SymbolKind>()?;
    m.add_class::<DiagnosticSeverity>()?;
    m.add_function(wrap_pyfunction!(detect_language_from_extension, m)?)?;
    m.add_function(wrap_pyfunction!(detect_language_from_path, m)?)?;
    m.add_function(wrap_pyfunction!(detect_language_from_content, m)?)?;
    m.add_function(wrap_pyfunction!(root_node_info, m)?)?;
    m.add_function(wrap_pyfunction!(find_nodes_by_type, m)?)?;
    m.add_function(wrap_pyfunction!(named_children_info, m)?)?;
    m.add_function(wrap_pyfunction!(parse_string, m)?)?;
    m.add_function(wrap_pyfunction!(tree_contains_node_type, m)?)?;
    m.add_function(wrap_pyfunction!(tree_has_error_nodes, m)?)?;
    m.add_function(wrap_pyfunction!(tree_to_sexp, m)?)?;
    m.add_function(wrap_pyfunction!(tree_error_count, m)?)?;
    m.add_function(wrap_pyfunction!(get_highlights_query, m)?)?;
    m.add_function(wrap_pyfunction!(get_injections_query, m)?)?;
    m.add_function(wrap_pyfunction!(get_locals_query, m)?)?;
    m.add_function(wrap_pyfunction!(run_query, m)?)?;
    m.add_function(wrap_pyfunction!(get_language, m)?)?;
    m.add_function(wrap_pyfunction!(get_parser, m)?)?;
    m.add_function(wrap_pyfunction!(available_languages, m)?)?;
    m.add_function(wrap_pyfunction!(has_language, m)?)?;
    m.add_function(wrap_pyfunction!(language_count, m)?)?;
    m.add_function(wrap_pyfunction!(process, m)?)?;
    m.add_function(wrap_pyfunction!(extract_patterns, m)?)?;
    m.add_function(wrap_pyfunction!(validate_extraction, m)?)?;
    m.add_function(wrap_pyfunction!(init, m)?)?;
    m.add_function(wrap_pyfunction!(configure, m)?)?;
    m.add_function(wrap_pyfunction!(download, m)?)?;
    m.add_function(wrap_pyfunction!(download_all, m)?)?;
    m.add_function(wrap_pyfunction!(manifest_languages, m)?)?;
    m.add_function(wrap_pyfunction!(downloaded_languages, m)?)?;
    m.add_function(wrap_pyfunction!(clean_cache, m)?)?;
    m.add_function(wrap_pyfunction!(cache_dir, m)?)?;
    m.add("LanguageNotFoundError", m.py().get_type::<LanguageNotFoundError>())?;
    m.add("DynamicLoadError", m.py().get_type::<DynamicLoadError>())?;
    m.add(
        "NullLanguagePointerError",
        m.py().get_type::<NullLanguagePointerError>(),
    )?;
    m.add("ParserSetupError", m.py().get_type::<ParserSetupError>())?;
    m.add("LockPoisonedError", m.py().get_type::<LockPoisonedError>())?;
    m.add("ConfigError", m.py().get_type::<ConfigError>())?;
    m.add("ParseFailedError", m.py().get_type::<ParseFailedError>())?;
    m.add("QueryError", m.py().get_type::<QueryError>())?;
    m.add("InvalidRangeError", m.py().get_type::<InvalidRangeError>())?;
    m.add("IoError", m.py().get_type::<IoError>())?;
    m.add("Error", m.py().get_type::<Error>())?;
    Ok(())
}
